'use client';

import { useState, useEffect } from 'react';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Plus, Gift, Users, Star, Award, TrendingUp } from 'lucide-react';
import axios from 'axios';
import { toast } from 'sonner';

interface LoyaltyProgram {
  id: number;
  name: string;
  points_per_currency: number;
  redemption_rate: number;
  min_points_to_redeem: number;
  expiry_months: number;
  status: string;
  description: string | null;
  loyalty_rewards?: LoyaltyReward[];
}

interface LoyaltyReward {
  id: number;
  name: string;
  description: string | null;
  points_required: number;
  reward_type: string;
  reward_value: number | null;
  status: string;
}

export default function LoyaltyPage() {
  const [programs, setPrograms] = useState<LoyaltyProgram[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  const [rewardDialogOpen, setRewardDialogOpen] = useState(false);
  const [selectedProgram, setSelectedProgram] = useState<LoyaltyProgram | null>(null);
  const [formData, setFormData] = useState({
    name: '',
    points_per_currency: '1.00',
    redemption_rate: '0.01',
    min_points_to_redeem: '100',
    expiry_months: '12',
    description: '',
  });
  const [rewardFormData, setRewardFormData] = useState({
    name: '',
    description: '',
    points_required: '',
    reward_type: 'discount',
    reward_value: '',
  });

  useEffect(() => {
    fetchPrograms();
  }, []);

  const fetchPrograms = async () => {
    try {
      const response = await axios.get('/api/loyalty');
      setPrograms(response.data.data);
    } catch (error) {
      toast.error('Failed to fetch loyalty programs');
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await axios.post('/api/loyalty', formData);
      toast.success('Loyalty program created successfully');
      setDialogOpen(false);
      setFormData({
        name: '',
        points_per_currency: '1.00',
        redemption_rate: '0.01',
        min_points_to_redeem: '100',
        expiry_months: '12',
        description: '',
      });
      fetchPrograms();
    } catch (error) {
      toast.error('Failed to create loyalty program');
    }
  };

  const handleRewardSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedProgram) return;
    try {
      await axios.post(`/api/loyalty/${selectedProgram.id}/rewards`, rewardFormData);
      toast.success('Reward added successfully');
      setRewardDialogOpen(false);
      setRewardFormData({
        name: '',
        description: '',
        points_required: '',
        reward_type: 'discount',
        reward_value: '',
      });
      fetchPrograms();
    } catch (error) {
      toast.error('Failed to add reward');
    }
  };

  const getRewardTypeIcon = (type: string) => {
    switch (type) {
      case 'discount':
        return <TrendingUp className="h-4 w-4" />;
      case 'free_item':
        return <Gift className="h-4 w-4" />;
      case 'cashback':
        return <Award className="h-4 w-4" />;
      default:
        return <Star className="h-4 w-4" />;
    }
  };

  if (loading) {
    return <div className="flex items-center justify-center h-screen">Loading...</div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold">Loyalty Programs</h1>
          <p className="text-muted-foreground">Manage customer loyalty and rewards</p>
        </div>
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger asChild>
            <Button>
              <Plus className="mr-2 h-4 w-4" />
              Create Program
            </Button>
          </DialogTrigger>
          <DialogContent>
            <DialogHeader>
              <DialogTitle>Create Loyalty Program</DialogTitle>
              <DialogDescription>Set up a new loyalty program to reward customers</DialogDescription>
            </DialogHeader>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <Label htmlFor="name">Program Name</Label>
                <Input
                  id="name"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="e.g., VIP Rewards"
                  required
                />
              </div>
              <div>
                <Label htmlFor="points_per_currency">Points per Currency Unit</Label>
                <Input
                  id="points_per_currency"
                  type="number"
                  step="0.01"
                  value={formData.points_per_currency}
                  onChange={(e) => setFormData({ ...formData, points_per_currency: e.target.value })}
                  placeholder="1.00"
                  required
                />
              </div>
              <div>
                <Label htmlFor="redemption_rate">Redemption Rate</Label>
                <Input
                  id="redemption_rate"
                  type="number"
                  step="0.01"
                  value={formData.redemption_rate}
                  onChange={(e) => setFormData({ ...formData, redemption_rate: e.target.value })}
                  placeholder="0.01"
                  required
                />
              </div>
              <div>
                <Label htmlFor="min_points_to_redeem">Minimum Points to Redeem</Label>
                <Input
                  id="min_points_to_redeem"
                  type="number"
                  value={formData.min_points_to_redeem}
                  onChange={(e) => setFormData({ ...formData, min_points_to_redeem: e.target.value })}
                  placeholder="100"
                  required
                />
              </div>
              <div>
                <Label htmlFor="expiry_months">Points Expiry (Months)</Label>
                <Input
                  id="expiry_months"
                  type="number"
                  value={formData.expiry_months}
                  onChange={(e) => setFormData({ ...formData, expiry_months: e.target.value })}
                  placeholder="12"
                  required
                />
              </div>
              <div>
                <Label htmlFor="description">Description</Label>
                <Input
                  id="description"
                  value={formData.description}
                  onChange={(e) => setFormData({ ...formData, description: e.target.value })}
                  placeholder="Program description"
                />
              </div>
              <Button type="submit" className="w-full">Create Program</Button>
            </form>
          </DialogContent>
        </Dialog>
      </div>

      <Tabs defaultValue="programs" className="space-y-4">
        <TabsList>
          <TabsTrigger value="programs">Programs</TabsTrigger>
          <TabsTrigger value="rewards">Rewards</TabsTrigger>
          <TabsTrigger value="customers">Customers</TabsTrigger>
        </TabsList>

        <TabsContent value="programs" className="space-y-4">
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-3">
            {programs.map((program) => (
              <Card key={program.id}>
                <CardHeader>
                  <div className="flex justify-between items-start">
                    <div>
                      <CardTitle className="text-lg">{program.name}</CardTitle>
                      <CardDescription>{program.description || 'No description'}</CardDescription>
                    </div>
                    <Badge variant={program.status === 'active' ? 'default' : 'secondary'}>
                      {program.status}
                    </Badge>
                  </div>
                </CardHeader>
                <CardContent className="space-y-3">
                  <div className="flex items-center gap-2 text-sm">
                    <Star className="h-4 w-4 text-muted-foreground" />
                    <span className="text-muted-foreground">{program.points_per_currency} points per $1</span>
                  </div>
                  <div className="flex items-center gap-2 text-sm">
                    <Award className="h-4 w-4 text-muted-foreground" />
                    <span className="text-muted-foreground">{program.min_points_to_redeem} min points to redeem</span>
                  </div>
                  <div className="flex items-center gap-2 text-sm">
                    <TrendingUp className="h-4 w-4 text-muted-foreground" />
                    <span className="text-muted-foreground">{program.expiry_months} months expiry</span>
                  </div>
                  <div className="flex items-center gap-2 text-sm">
                    <Gift className="h-4 w-4 text-muted-foreground" />
                    <span className="text-muted-foreground">{program.loyalty_rewards?.length || 0} rewards available</span>
                  </div>
                  <Button
                    variant="outline"
                    className="w-full"
                    onClick={() => {
                      setSelectedProgram(program);
                      setRewardDialogOpen(true);
                    }}
                  >
                    Add Reward
                  </Button>
                </CardContent>
              </Card>
            ))}
          </div>

          {programs.length === 0 && (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <Star className="h-12 w-12 text-muted-foreground mb-4" />
                <p className="text-muted-foreground text-center">No loyalty programs created yet</p>
                <p className="text-sm text-muted-foreground text-center mt-2">Create your first program to start rewarding customers</p>
              </CardContent>
            </Card>
          )}
        </TabsContent>

        <TabsContent value="rewards" className="space-y-4">
          <div className="grid gap-4">
            {programs.flatMap(program => 
              program.loyalty_rewards?.map(reward => (
                <Card key={reward.id}>
                  <CardHeader>
                    <div className="flex justify-between items-start">
                      <div className="flex items-center gap-2">
                        {getRewardTypeIcon(reward.reward_type)}
                        <CardTitle className="text-lg">{reward.name}</CardTitle>
                      </div>
                      <Badge>{reward.points_required} points</Badge>
                    </div>
                    <CardDescription>{reward.description || 'No description'}</CardDescription>
                  </CardHeader>
                  <CardContent>
                    <div className="flex items-center gap-2 text-sm text-muted-foreground">
                      <span>Program: {program.name}</span>
                      <span>•</span>
                      <span>Type: {reward.reward_type}</span>
                      {reward.reward_value && (
                        <>
                          <span>•</span>
                          <span>Value: ${reward.reward_value.toFixed(2)}</span>
                        </>
                      )}
                    </div>
                  </CardContent>
                </Card>
              )) || []
            )}
          </div>

          {programs.flatMap(p => p.loyalty_rewards?.length || 0).reduce((a, b) => a + b, 0) === 0 && (
            <Card>
              <CardContent className="flex flex-col items-center justify-center py-12">
                <Gift className="h-12 w-12 text-muted-foreground mb-4" />
                <p className="text-muted-foreground text-center">No rewards created yet</p>
                <p className="text-sm text-muted-foreground text-center mt-2">Add rewards to your loyalty programs</p>
              </CardContent>
            </Card>
          )}
        </TabsContent>

        <TabsContent value="customers" className="space-y-4">
          <Card>
            <CardHeader>
              <CardTitle>Customer Enrollment</CardTitle>
              <CardDescription>Enroll customers in loyalty programs</CardDescription>
            </CardHeader>
            <CardContent>
              <form className="space-y-4">
                <div>
                  <Label htmlFor="customer">Select Customer</Label>
                  <Select>
                    <SelectTrigger>
                      <SelectValue placeholder="Choose a customer" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="1">Customer 1</SelectItem>
                      <SelectItem value="2">Customer 2</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div>
                  <Label htmlFor="program">Select Program</Label>
                  <Select>
                    <SelectTrigger>
                      <SelectValue placeholder="Choose a program" />
                    </SelectTrigger>
                    <SelectContent>
                      {programs.map(program => (
                        <SelectItem key={program.id} value={program.id.toString()}>
                          {program.name}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                <Button type="button" className="w-full">Enroll Customer</Button>
              </form>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      <Dialog open={rewardDialogOpen} onOpenChange={setRewardDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Add Reward to {selectedProgram?.name}</DialogTitle>
            <DialogDescription>Create a new reward for this loyalty program</DialogDescription>
          </DialogHeader>
          <form onSubmit={handleRewardSubmit} className="space-y-4">
            <div>
              <Label htmlFor="reward_name">Reward Name</Label>
              <Input
                id="reward_name"
                value={rewardFormData.name}
                onChange={(e) => setRewardFormData({ ...rewardFormData, name: e.target.value })}
                placeholder="e.g., 10% Discount"
                required
              />
            </div>
            <div>
              <Label htmlFor="reward_description">Description</Label>
              <Input
                id="reward_description"
                value={rewardFormData.description}
                onChange={(e) => setRewardFormData({ ...rewardFormData, description: e.target.value })}
                placeholder="Reward description"
              />
            </div>
            <div>
              <Label htmlFor="points_required">Points Required</Label>
              <Input
                id="points_required"
                type="number"
                value={rewardFormData.points_required}
                onChange={(e) => setRewardFormData({ ...rewardFormData, points_required: e.target.value })}
                placeholder="100"
                required
              />
            </div>
            <div>
              <Label htmlFor="reward_type">Reward Type</Label>
              <Select value={rewardFormData.reward_type} onValueChange={(value) => setRewardFormData({ ...rewardFormData, reward_type: value })}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="discount">Discount</SelectItem>
                  <SelectItem value="free_item">Free Item</SelectItem>
                  <SelectItem value="cashback">Cashback</SelectItem>
                  <SelectItem value="upgrade">Upgrade</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div>
              <Label htmlFor="reward_value">Reward Value</Label>
              <Input
                id="reward_value"
                type="number"
                step="0.01"
                value={rewardFormData.reward_value}
                onChange={(e) => setRewardFormData({ ...rewardFormData, reward_value: e.target.value })}
                placeholder="0.00"
              />
            </div>
            <Button type="submit" className="w-full">Add Reward</Button>
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client"

import * as React from "react"
import axios from "@/lib/axios"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { getAuthToken, getUser } from "@/lib/auth"

/**
 * Debug component to diagnose orders loading issues
 * This component helps identify authentication and API connectivity problems
 */
export default function DebugOrdersPage() {
    const [diagnostics, setDiagnostics] = React.useState<any>({})
    const [loading, setLoading] = React.useState(false)

    const runDiagnostics = async () => {
        setLoading(true)
        const results: any = {}

        // 1. Check authentication token
        const token = getAuthToken()
        results.hasToken = !!token
        results.tokenLength = token?.length || 0
        results.tokenPreview = token ? `${token.substring(0, 20)}...` : 'No token'

        // 2. Check user data
        const user = getUser()
        results.hasUser = !!user
        results.user = user

        // 3. Check localStorage
        results.localStorage = {
            auth_token: localStorage.getItem('auth_token') ? 'Present' : 'Missing',
            user: localStorage.getItem('user') ? 'Present' : 'Missing',
        }

        // 4. Check cookies
        results.cookies = {
            auth_token: document.cookie.includes('auth_token') ? 'Present' : 'Missing',
        }

        // 5. Test API connectivity
        try {
            const response = await axios.get('/profile')
            results.profileTest = {
                success: true,
                status: response.status,
                data: response.data,
            }
        } catch (error: any) {
            results.profileTest = {
                success: false,
                status: error.response?.status,
                message: error.message,
                data: error.response?.data,
            }
        }

        // 6. Test orders endpoint
        try {
            const response = await axios.get('/orders')
            results.ordersTest = {
                success: true,
                status: response.status,
                dataCount: response.data?.data?.length || 0,
            }
        } catch (error: any) {
            results.ordersTest = {
                success: false,
                status: error.response?.status,
                message: error.message,
                data: error.response?.data,
                code: error.code,
            }
        }

        // 7. Check axios configuration
        results.axiosConfig = {
            baseURL: axios.defaults.baseURL,
            headers: axios.defaults.headers,
        }

        setDiagnostics(results)
        setLoading(false)
    }

    React.useEffect(() => {
        runDiagnostics()
    }, [])

    return (
        <div className="p-6 space-y-6">
            <Card>
                <CardHeader>
                    <CardTitle>Orders Loading Diagnostics</CardTitle>
                </CardHeader>
                <CardContent className="space-y-4">
                    <Button onClick={runDiagnostics} disabled={loading}>
                        {loading ? 'Running...' : 'Run Diagnostics'}
                    </Button>

                    <div className="space-y-4">
                        <div>
                            <h3 className="font-semibold mb-2">1. Authentication Token</h3>
                            <pre className="bg-gray-100 p-3 rounded text-sm overflow-auto">
                                {JSON.stringify({
                                    hasToken: diagnostics.hasToken,
                                    tokenLength: diagnostics.tokenLength,
                                    tokenPreview: diagnostics.tokenPreview,
                                }, null, 2)}
                            </pre>
                        </div>

                        <div>
                            <h3 className="font-semibold mb-2">2. User Data</h3>
                            <pre className="bg-gray-100 p-3 rounded text-sm overflow-auto">
                                {JSON.stringify({
                                    hasUser: diagnostics.hasUser,
                                    user: diagnostics.user,
                                }, null, 2)}
                            </pre>
                        </div>

                        <div>
                            <h3 className="font-semibold mb-2">3. LocalStorage</h3>
                            <pre className="bg-gray-100 p-3 rounded text-sm overflow-auto">
                                {JSON.stringify(diagnostics.localStorage, null, 2)}
                            </pre>
                        </div>

                        <div>
                            <h3 className="font-semibold mb-2">4. Cookies</h3>
                            <pre className="bg-gray-100 p-3 rounded text-sm overflow-auto">
                                {JSON.stringify(diagnostics.cookies, null, 2)}
                            </pre>
                        </div>

                        <div>
                            <h3 className="font-semibold mb-2">5. Profile API Test</h3>
                            <pre className={`p-3 rounded text-sm overflow-auto ${diagnostics.profileTest?.success ? 'bg-green-100' : 'bg-red-100'
                                }`}>
                                {JSON.stringify(diagnostics.profileTest, null, 2)}
                            </pre>
                        </div>

                        <div>
                            <h3 className="font-semibold mb-2">6. Orders API Test</h3>
                            <pre className={`p-3 rounded text-sm overflow-auto ${diagnostics.ordersTest?.success ? 'bg-green-100' : 'bg-red-100'
                                }`}>
                                {JSON.stringify(diagnostics.ordersTest, null, 2)}
                            </pre>
                        </div>

                        <div>
                            <h3 className="font-semibold mb-2">7. Axios Configuration</h3>
                            <pre className="bg-gray-100 p-3 rounded text-sm overflow-auto">
                                {JSON.stringify(diagnostics.axiosConfig, null, 2)}
                            </pre>
                        </div>
                    </div>

                    <div className="mt-6 p-4 bg-blue-50 rounded">
                        <h3 className="font-semibold mb-2">Troubleshooting Guide</h3>
                        <ul className="list-disc list-inside space-y-1 text-sm">
                            <li>If <strong>hasToken</strong> is false: User needs to log in</li>
                            <li>If <strong>profileTest</strong> fails with 401: Token is invalid or expired</li>
                            <li>If <strong>ordersTest</strong> fails with 401: Same as profile test</li>
                            <li>If <strong>ordersTest</strong> fails with 403: User lacks permissions</li>
                            <li>If <strong>ordersTest</strong> fails with ERR_NETWORK: Backend is not running</li>
                            <li>If <strong>ordersTest</strong> fails with 500: Server error, check Laravel logs</li>
                        </ul>
                    </div>
                </CardContent>
            </Card>
        </div>
    )
}

"use client"

import * as React from "react"
import axios from "@/lib/axios"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Input } from "@/components/ui/input"
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogFooter
} from "@/components/ui/dialog"
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select"
import {
    SearchIcon,
    RefreshCwIcon,
    EyeIcon,
    CheckCircleIcon,
    XCircleIcon,
    ClockIcon,
    DollarSignIcon,
    UtensilsIcon,
    PackageIcon,
    Loader2Icon
} from "lucide-react"
import { toast } from "react-hot-toast"

interface OrderItem {
    id: number
    product_name: string
    variant_name: string
    quantity: number
    unit_price: number
    subtotal: number
    status: string
}

interface Order {
    id: number
    table_number: string
    type: string
    total: number
    tax: number
    discount: number
    status: string
    payment_method: string
    payment_status: string
    paid_amount: number | null
    change_amount: number | null
    paid_at: string | null
    items: OrderItem[]
    created_at: string
    created_at_human: string
}

export default function OrdersPage() {
    const [orders, setOrders] = React.useState<Order[]>([])
    const [loading, setLoading] = React.useState(true)
    const [search, setSearch] = React.useState("")
    const [statusFilter, setStatusFilter] = React.useState<string>("all")
    const [paymentFilter, setPaymentFilter] = React.useState<string>("all")
    const [selectedOrder, setSelectedOrder] = React.useState<Order | null>(null)
    const [detailsOpen, setDetailsOpen] = React.useState(false)
    const [updating, setUpdating] = React.useState(false)

    const fetchOrders = React.useCallback(async () => {
        try {
            setLoading(true)
            const res = await axios.get("/orders")
            setOrders(res.data.data)
        } catch (error: any) {
            console.error("Failed to fetch orders:", error)

            // Handle specific error cases
            if (error.response?.status === 401) {
                toast.error("Session expired. Please log in again.")
                // Optionally redirect to login after a delay
                setTimeout(() => {
                    window.location.href = '/auth/login'
                }, 2000)
            } else if (error.response?.status === 403) {
                toast.error("You don't have permission to view orders")
            } else if (error.response?.status === 500) {
                toast.error("Server error. Please try again later.")
            } else if (error.code === 'ERR_NETWORK') {
                toast.error("Cannot connect to server. Please check if backend is running.")
            } else {
                toast.error(error.response?.data?.message || "Failed to load orders")
            }
        } finally {
            setLoading(false)
        }
    }, [])

    React.useEffect(() => {
        // Check authentication before fetching
        const token = localStorage.getItem('auth_token')
        if (!token) {
            toast.error("Please log in to view orders")
            setTimeout(() => {
                window.location.href = '/auth/login'
            }, 1500)
            return
        }

        fetchOrders()
    }, [fetchOrders])

    const filtered = orders.filter(order => {
        const matchesSearch =
            order.table_number.toLowerCase().includes(search.toLowerCase()) ||
            order.id.toString().includes(search)
        const matchesStatus = statusFilter === "all" || order.status === statusFilter
        const matchesPayment = paymentFilter === "all" || order.payment_status === paymentFilter
        return matchesSearch && matchesStatus && matchesPayment
    })

    const handleUpdateStatus = async (orderId: number, newStatus: string) => {
        setUpdating(true)
        try {
            await axios.patch(`/orders/${orderId}/status`, { status: newStatus })
            toast.success("Order status updated")
            fetchOrders()
            if (selectedOrder?.id === orderId) {
                setDetailsOpen(false)
                setSelectedOrder(null)
            }
        } catch (error: any) {
            console.error("Failed to update status:", error)
            toast.error(error.response?.data?.message || "Failed to update status")
        } finally {
            setUpdating(false)
        }
    }

    const handleUpdatePayment = async (orderId: number, paymentStatus: string) => {
        setUpdating(true)
        try {
            const order = orders.find(o => o.id === orderId)
            await axios.patch(`/orders/${orderId}/payment`, {
                payment_status: paymentStatus,
                paid_amount: order?.total,
                change_amount: 0
            })
            toast.success("Payment status updated")
            fetchOrders()
            if (selectedOrder?.id === orderId) {
                setDetailsOpen(false)
                setSelectedOrder(null)
            }
        } catch (error: any) {
            console.error("Failed to update payment:", error)
            toast.error(error.response?.data?.message || "Failed to update payment")
        } finally {
            setUpdating(false)
        }
    }

    const handleCancelOrder = async (orderId: number) => {
        if (!confirm("Are you sure you want to cancel this order? Stock will be restored.")) {
            return
        }

        setUpdating(true)
        try {
            await axios.post(`/orders/${orderId}/cancel`)
            toast.success("Order cancelled and stock restored")
            fetchOrders()
            if (selectedOrder?.id === orderId) {
                setDetailsOpen(false)
                setSelectedOrder(null)
            }
        } catch (error: any) {
            console.error("Failed to cancel order:", error)
            toast.error(error.response?.data?.message || "Failed to cancel order")
        } finally {
            setUpdating(false)
        }
    }

    const getStatusColor = (status: string) => {
        const colors: Record<string, string> = {
            pending: "bg-yellow-500",
            cooking: "bg-orange-500",
            ready: "bg-blue-500",
            served: "bg-green-500",
            paid: "bg-emerald-500",
            completed: "bg-gray-500",
            cancelled: "bg-red-500"
        }
        return colors[status] || "bg-gray-500"
    }

    const getPaymentStatusColor = (status: string) => {
        const colors: Record<string, string> = {
            pending: "bg-yellow-500",
            paid: "bg-green-500",
            refunded: "bg-blue-500",
            cancelled: "bg-red-500"
        }
        return colors[status] || "bg-gray-500"
    }

    return (
        <div className="p-6 space-y-6">
            {/* Header */}
            <div className="flex items-center justify-between">
                <div>
                    <h1 className="text-3xl font-bold">Orders Management</h1>
                    <p className="text-muted-foreground">Track and manage all orders</p>
                </div>
                <Button onClick={fetchOrders} disabled={loading}>
                    <RefreshCwIcon className={`size-4 mr-2 ${loading ? 'animate-spin' : ''}`} />
                    Refresh
                </Button>
            </div>

            {/* Filters */}
            <Card>
                <CardContent className="p-4">
                    <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                        <div className="relative">
                            <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
                            <Input
                                placeholder="Search by order ID or table..."
                                className="pl-9"
                                value={search}
                                onChange={e => setSearch(e.target.value)}
                            />
                        </div>
                        <Select value={statusFilter} onValueChange={setStatusFilter}>
                            <SelectTrigger>
                                <SelectValue placeholder="Order Status" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">All Status</SelectItem>
                                <SelectItem value="pending">Pending</SelectItem>
                                <SelectItem value="cooking">Cooking</SelectItem>
                                <SelectItem value="ready">Ready</SelectItem>
                                <SelectItem value="served">Served</SelectItem>
                                <SelectItem value="paid">Paid</SelectItem>
                                <SelectItem value="completed">Completed</SelectItem>
                                <SelectItem value="cancelled">Cancelled</SelectItem>
                            </SelectContent>
                        </Select>
                        <Select value={paymentFilter} onValueChange={setPaymentFilter}>
                            <SelectTrigger>
                                <SelectValue placeholder="Payment Status" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">All Payments</SelectItem>
                                <SelectItem value="pending">Pending</SelectItem>
                                <SelectItem value="paid">Paid</SelectItem>
                                <SelectItem value="refunded">Refunded</SelectItem>
                                <SelectItem value="cancelled">Cancelled</SelectItem>
                            </SelectContent>
                        </Select>
                        <div className="flex items-center gap-2 text-sm text-muted-foreground">
                            <span className="font-medium">{filtered.length}</span> orders found
                        </div>
                    </div>
                </CardContent>
            </Card>

            {/* Orders List */}
            {loading ? (
                <div className="flex items-center justify-center h-64">
                    <Loader2Icon className="size-8 animate-spin text-muted-foreground" />
                </div>
            ) : filtered.length === 0 ? (
                <Card>
                    <CardContent className="flex flex-col items-center justify-center h-64 text-muted-foreground">
                        <PackageIcon className="size-12 mb-2" />
                        <p>No orders found</p>
                    </CardContent>
                </Card>
            ) : (
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                    {filtered.map(order => (
                        <Card key={order.id} className="hover:shadow-md transition-shadow">
                            <CardHeader className="pb-3">
                                <div className="flex items-start justify-between">
                                    <div>
                                        <CardTitle className="text-lg">Order #{order.id}</CardTitle>
                                        <p className="text-sm text-muted-foreground flex items-center gap-1 mt-1">
                                            {order.type === 'dine_in' ? (
                                                <><UtensilsIcon className="size-3" /> {order.table_number}</>
                                            ) : (
                                                <><PackageIcon className="size-3" /> Takeaway</>
                                            )}
                                        </p>
                                    </div>
                                    <Badge className={getStatusColor(order.status)}>
                                        {order.status}
                                    </Badge>
                                </div>
                            </CardHeader>
                            <CardContent className="space-y-3">
                                <div className="space-y-1 text-sm">
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Items:</span>
                                        <span className="font-medium">{order.items?.length || 0}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Total:</span>
                                        <span className="font-semibold text-primary">${order.total.toFixed(2)}</span>
                                    </div>
                                    <div className="flex justify-between items-center">
                                        <span className="text-muted-foreground">Payment:</span>
                                        <Badge variant="outline" className={getPaymentStatusColor(order.payment_status)}>
                                            {order.payment_status}
                                        </Badge>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Method:</span>
                                        <span className="capitalize">{order.payment_method}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Time:</span>
                                        <span>{order.created_at_human}</span>
                                    </div>
                                </div>

                                <div className="flex gap-2 pt-2">
                                    <Button
                                        variant="outline"
                                        size="sm"
                                        className="flex-1"
                                        onClick={() => {
                                            setSelectedOrder(order)
                                            setDetailsOpen(true)
                                        }}
                                    >
                                        <EyeIcon className="size-3 mr-1" />
                                        Details
                                    </Button>
                                    {order.payment_status === 'pending' && (
                                        <Button
                                            size="sm"
                                            className="flex-1"
                                            onClick={() => handleUpdatePayment(order.id, 'paid')}
                                            disabled={updating}
                                        >
                                            <CheckCircleIcon className="size-3 mr-1" />
                                            Mark Paid
                                        </Button>
                                    )}
                                </div>
                            </CardContent>
                        </Card>
                    ))}
                </div>
            )}

            {/* Order Details Dialog */}
            <Dialog open={detailsOpen} onOpenChange={setDetailsOpen}>
                <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                    <DialogHeader>
                        <DialogTitle>Order #{selectedOrder?.id} Details</DialogTitle>
                    </DialogHeader>
                    {selectedOrder && (
                        <div className="space-y-4">
                            {/* Order Info */}
                            <Card>
                                <CardHeader>
                                    <CardTitle className="text-base">Order Information</CardTitle>
                                </CardHeader>
                                <CardContent className="grid grid-cols-2 gap-3 text-sm">
                                    <div>
                                        <span className="text-muted-foreground">Type:</span>
                                        <p className="font-medium capitalize flex items-center gap-1">
                                            {selectedOrder.type === 'dine_in' ? (
                                                <><UtensilsIcon className="size-3" /> Dine In</>
                                            ) : (
                                                <><PackageIcon className="size-3" /> Takeaway</>
                                            )}
                                        </p>
                                    </div>
                                    <div>
                                        <span className="text-muted-foreground">Table:</span>
                                        <p className="font-medium">{selectedOrder.table_number}</p>
                                    </div>
                                    <div>
                                        <span className="text-muted-foreground">Status:</span>
                                        <Badge className={getStatusColor(selectedOrder.status)}>
                                            {selectedOrder.status}
                                        </Badge>
                                    </div>
                                    <div>
                                        <span className="text-muted-foreground">Created:</span>
                                        <p className="font-medium">{selectedOrder.created_at_human}</p>
                                    </div>
                                </CardContent>
                            </Card>

                            {/* Payment Info */}
                            <Card>
                                <CardHeader>
                                    <CardTitle className="text-base">Payment Information</CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-2 text-sm">
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Method:</span>
                                        <span className="font-medium capitalize">{selectedOrder.payment_method}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Status:</span>
                                        <Badge className={getPaymentStatusColor(selectedOrder.payment_status)}>
                                            {selectedOrder.payment_status}
                                        </Badge>
                                    </div>
                                    {selectedOrder.paid_amount && (
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Paid Amount:</span>
                                            <span className="font-medium">${selectedOrder.paid_amount.toFixed(2)}</span>
                                        </div>
                                    )}
                                    {selectedOrder.change_amount && selectedOrder.change_amount > 0 && (
                                        <div className="flex justify-between text-green-600">
                                            <span>Change:</span>
                                            <span className="font-medium">${selectedOrder.change_amount.toFixed(2)}</span>
                                        </div>
                                    )}
                                </CardContent>
                            </Card>

                            {/* Items */}
                            <Card>
                                <CardHeader>
                                    <CardTitle className="text-base">Order Items</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <ScrollArea className="max-h-48">
                                        <div className="space-y-2">
                                            {selectedOrder.items?.map(item => (
                                                <div key={item.id} className="flex justify-between items-center p-2 border rounded">
                                                    <div>
                                                        <p className="font-medium text-sm">{item.product_name}</p>
                                                        <p className="text-xs text-muted-foreground">{item.variant_name}</p>
                                                    </div>
                                                    <div className="text-right">
                                                        <p className="text-sm">${item.unit_price.toFixed(2)} × {item.quantity}</p>
                                                        <p className="text-sm font-semibold">${item.subtotal.toFixed(2)}</p>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </ScrollArea>
                                </CardContent>
                            </Card>

                            {/* Totals */}
                            <Card>
                                <CardContent className="p-4 space-y-2 text-sm">
                                    <div className="flex justify-between">
                                        <span>Subtotal:</span>
                                        <span>${(selectedOrder.total - selectedOrder.tax + selectedOrder.discount).toFixed(2)}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span>Tax:</span>
                                        <span>${selectedOrder.tax.toFixed(2)}</span>
                                    </div>
                                    {selectedOrder.discount > 0 && (
                                        <div className="flex justify-between text-green-600">
                                            <span>Discount:</span>
                                            <span>-${selectedOrder.discount.toFixed(2)}</span>
                                        </div>
                                    )}
                                    <div className="flex justify-between text-lg font-bold pt-2 border-t">
                                        <span>Total:</span>
                                        <span className="text-primary">${selectedOrder.total.toFixed(2)}</span>
                                    </div>
                                </CardContent>
                            </Card>

                            {/* Actions */}
                            <div className="flex gap-2">
                                {selectedOrder.status !== 'cancelled' && selectedOrder.status !== 'completed' && (
                                    <>
                                        {selectedOrder.status === 'pending' && (
                                            <Button
                                                onClick={() => handleUpdateStatus(selectedOrder.id, 'cooking')}
                                                disabled={updating}
                                                className="flex-1"
                                            >
                                                <ClockIcon className="size-4 mr-2" />
                                                Start Cooking
                                            </Button>
                                        )}
                                        {selectedOrder.status === 'cooking' && (
                                            <Button
                                                onClick={() => handleUpdateStatus(selectedOrder.id, 'ready')}
                                                disabled={updating}
                                                className="flex-1"
                                            >
                                                <CheckCircleIcon className="size-4 mr-2" />
                                                Mark Ready
                                            </Button>
                                        )}
                                        {selectedOrder.status === 'ready' && (
                                            <Button
                                                onClick={() => handleUpdateStatus(selectedOrder.id, 'served')}
                                                disabled={updating}
                                                className="flex-1"
                                            >
                                                <UtensilsIcon className="size-4 mr-2" />
                                                Mark Served
                                            </Button>
                                        )}
                                        {selectedOrder.payment_status === 'pending' && (
                                            <Button
                                                onClick={() => handleUpdatePayment(selectedOrder.id, 'paid')}
                                                disabled={updating}
                                                variant="default"
                                                className="flex-1"
                                            >
                                                <DollarSignIcon className="size-4 mr-2" />
                                                Mark as Paid
                                            </Button>
                                        )}
                                        <Button
                                            onClick={() => handleCancelOrder(selectedOrder.id)}
                                            disabled={updating}
                                            variant="destructive"
                                        >
                                            <XCircleIcon className="size-4 mr-2" />
                                            Cancel Order
                                        </Button>
                                    </>
                                )}
                            </div>
                        </div>
                    )}
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setDetailsOpen(false)}>
                            Close
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

