import * as React from "react"
import axios from "@/lib/axios"
import { useCartStore } from "@/store/use-cart-store"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Input } from "@/components/ui/input"
import { Badge } from "@/components/ui/badge"
import { Separator } from "@/components/ui/separator"
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog"
import { Label } from "@/components/ui/label"
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group"
import {
    SearchIcon,
    MinusIcon,
    PlusIcon,
    TrashIcon,
    ShoppingCartIcon,
    CreditCardIcon,
    BanknoteIcon,
    PercentIcon,
    XIcon,
    PackageIcon,
    UtensilsIcon,
    Loader2Icon
} from "lucide-react"
import { toast } from "sonner"
import Image from "next/image"

interface Variant {
    id: number
    size_name: string
    price: number
    stock_qty?: number
    barcode?: string
}

interface Category {
    id: number
    name: string
    slug: string
    image?: string
    status: string
}

interface Product {
    id: number
    name: string
    description?: string
    image?: string
    status: string
    category?: Category
    variants: Variant[]
}

interface CafeTable {
    id: number
    number: string
    capacity: number
    status: 'available' | 'occupied' | 'cleaning' | 'reserved'
}

export default function POSPage() {
    const [products, setProducts] = React.useState<Product[]>([])
    const [categories, setCategories] = React.useState<Category[]>([])
    const [tables, setTables] = React.useState<CafeTable[]>([])
    const [search, setSearch] = React.useState("")
    const [selectedCategory, setSelectedCategory] = React.useState<number | null>(null)
    const [loading, setLoading] = React.useState(true)
    const [checkoutOpen, setCheckoutOpen] = React.useState(false)
    const [orderType, setOrderType] = React.useState<"dine_in" | "takeaway">("dine_in")
    const [selectedTable, setSelectedTable] = React.useState<number | null>(null)
    const [paymentMethod, setPaymentMethod] = React.useState<"cash" | "card">("cash")
    const [cashAmount, setCashAmount] = React.useState("")
    const [processingOrder, setProcessingOrder] = React.useState(false)
    const [selectedVariant, setSelectedVariant] = React.useState<{ product: Product; variant: Variant } | null>(null)

    const cart = useCartStore()

    const fetchData = React.useCallback(async () => {
        try {
            setLoading(true)
            const [productsRes, categoriesRes, tablesRes] = await Promise.all([
                axios.get("/products?per_page=100"),
                axios.get("/categories"),
                axios.get("/tables")
            ])
            setProducts(productsRes.data.data)
            setCategories(categoriesRes.data.data.filter((c: Category) => c.status === 'active'))
            setTables(tablesRes.data.data)
        } catch (error) {
            console.error("Failed to fetch data:", error)
            toast.error("Failed to load products")
        } finally {
            setLoading(false)
        }
    }, [])

    React.useEffect(() => {
        fetchData()
    }, [fetchData])

    // Keyboard shortcuts
    React.useEffect(() => {
        const handleKeyPress = (e: KeyboardEvent) => {
            if (e.key === 'F1') {
                e.preventDefault()
                document.getElementById('search-input')?.focus()
            }
            if (e.key === 'F2' && cart.items.length > 0) {
                e.preventDefault()
                setCheckoutOpen(true)
            }
            if (e.key === 'Escape') {
                setCheckoutOpen(false)
                setSelectedVariant(null)
            }
        }
        window.addEventListener('keydown', handleKeyPress)
        return () => window.removeEventListener('keydown', handleKeyPress)
    }, [cart.items.length])

    const filtered = products.filter(p => {
        const matchesSearch = p.name.toLowerCase().includes(search.toLowerCase())
        const matchesCategory = !selectedCategory || p.category?.id === selectedCategory
        const isActive = p.status === 'active'
        const hasStock = p.variants.some(v => v.stock_qty === undefined || v.stock_qty > 0)
        return matchesSearch && matchesCategory && isActive && hasStock
    })

    const handleAddToCart = (product: Product, variant: Variant) => {
        // Check stock availability
        if (variant.stock_qty !== undefined && variant.stock_qty !== null) {
            const currentQty = cart.items.find(i => i.variant_id === variant.id)?.quantity || 0
            if (currentQty >= variant.stock_qty) {
                toast.error(`Only ${variant.stock_qty} items available in stock`)
                return
            }
        }

        cart.addItem({
            variant_id: variant.id,
            product_name: product.name,
            size_name: variant.size_name,
            price: variant.price
        })
        toast.success(`Added ${product.name} (${variant.size_name}) to cart`)
        setSelectedVariant(null)
    }

    const handleProductClick = (product: Product) => {
        if (product.variants.length === 1) {
            handleAddToCart(product, product.variants[0])
        } else {
            setSelectedVariant({ product, variant: product.variants[0] })
        }
    }

    // Get variant stock info for cart items
    const getVariantStock = (variantId: number): number | undefined => {
        for (const product of products) {
            const variant = product.variants.find(v => v.id === variantId)
            if (variant) return variant.stock_qty
        }
        return undefined
    }

    const handleCheckout = async () => {
        if (cart.items.length === 0) {
            toast.error("Cart is empty")
            return
        }

        // Check for out of stock items
        const outOfStockItems = cart.items.filter(item => {
            const stockQty = getVariantStock(item.variant_id)
            return stockQty !== undefined && item.quantity > stockQty
        })

        if (outOfStockItems.length > 0) {
            toast.error("Some items exceed available stock. Please adjust quantities.")
            return
        }

        // Validate table selection for dine-in
        if (orderType === "dine_in" && !selectedTable) {
            toast.error("Please select a table for dine-in orders")
            return
        }

        // Validate cash payment
        if (paymentMethod === "cash") {
            const cashValue = parseFloat(cashAmount)
            if (!cashAmount || isNaN(cashValue) || cashValue < total) {
                toast.error(`Cash amount must be at least $${total.toFixed(2)}`)
                return
            }
        }

        setProcessingOrder(true)
        try {
            const orderData = {
                type: orderType,
                table_id: orderType === "dine_in" ? selectedTable : null,
                payment_method: paymentMethod,
                paid_amount: paymentMethod === "cash" ? parseFloat(cashAmount) : total,
                items: cart.items.map(item => ({
                    product_variant_id: item.variant_id,
                    quantity: item.quantity,
                    unit_price: item.price,
                    subtotal: item.price * item.quantity
                }))
            }

            await axios.post("/orders", orderData)

            // Show change if cash payment
            if (paymentMethod === "cash") {
                const change = parseFloat(cashAmount) - total
                if (change > 0) {
                    toast.success(`Order placed! Change: $${change.toFixed(2)}`)
                } else {
                    toast.success("Order placed successfully!")
                }
            } else {
                toast.success("Order placed successfully!")
            }

            cart.clearCart()
            setCheckoutOpen(false)
            setOrderType("dine_in")
            setSelectedTable(null)
            setPaymentMethod("cash")
            setCashAmount("")

            // Refresh tables to update status
            const tablesRes = await axios.get("/tables")
            setTables(tablesRes.data.data)
        } catch (error: any) {
            console.error("Checkout failed:", error)
            toast.error(error.response?.data?.message || "Failed to process order")
        } finally {
            setProcessingOrder(false)
        }
    }

    const subtotal = cart.subtotal()
    const tax = subtotal * cart.taxRate
    const discount = cart.discount
    const total = cart.total()

    // Quick cash amount suggestions
    const suggestedAmounts = [
        Math.ceil(total),
        Math.ceil(total / 10) * 10,
        Math.ceil(total / 20) * 20,
        Math.ceil(total / 50) * 50
    ].filter((v, i, a) => a.indexOf(v) === i && v >= total).slice(0, 4)

    return (
        <div className="flex h-[calc(100vh-4rem)] bg-muted/30">
            {/* Main Product Area */}
            <div className="flex-1 flex flex-col p-4 gap-4 overflow-hidden">
                {/* Search and Categories */}
                <div className="space-y-3">
                    <div className="relative">
                        <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-muted-foreground" />
                        <Input
                            id="search-input"
                            placeholder="Search products (F1)..."
                            className="pl-9 h-11 bg-background"
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                        />
                    </div>

                    <ScrollArea className="w-full whitespace-nowrap">
                        <div className="flex gap-2 pb-2">
                            <Button
                                variant={selectedCategory === null ? "default" : "outline"}
                                size="sm"
                                onClick={() => setSelectedCategory(null)}
                                className="shrink-0"
                            >
                                All Products
                            </Button>
                            {categories.map(category => (
                                <Button
                                    key={category.id}
                                    variant={selectedCategory === category.id ? "default" : "outline"}
                                    size="sm"
                                    onClick={() => setSelectedCategory(category.id)}
                                    className="shrink-0"
                                >
                                    {category.name}
                                </Button>
                            ))}
                        </div>
                    </ScrollArea>
                </div>

                {/* Products Grid */}
                <ScrollArea className="flex-1">
                    {loading ? (
                        <div className="flex items-center justify-center h-64">
                            <Loader2Icon className="size-8 animate-spin text-muted-foreground" />
                        </div>
                    ) : filtered.length === 0 ? (
                        <div className="flex flex-col items-center justify-center h-64 text-muted-foreground">
                            <PackageIcon className="size-12 mb-2" />
                            <p>No products found</p>
                        </div>
                    ) : (
                        <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-3 pb-4">
                            {filtered.map(product => (
                                <Card
                                    key={product.id}
                                    className="cursor-pointer hover:shadow-md transition-all hover:scale-[1.02] group overflow-hidden"
                                    onClick={() => handleProductClick(product)}
                                >
                                    <CardContent className="p-0">
                                        <div className="aspect-square relative bg-muted">
                                            {product.image ? (
                                                <Image
                                                    src={product.image}
                                                    alt={product.name}
                                                    fill
                                                    className="object-cover"
                                                />
                                            ) : (
                                                <div className="w-full h-full flex items-center justify-center">
                                                    <PackageIcon className="size-12 text-muted-foreground/50" />
                                                </div>
                                            )}
                                            <div className="absolute top-2 right-2 flex flex-col gap-1">
                                                {product.variants.length > 1 && (
                                                    <Badge className="text-xs">
                                                        {product.variants.length} sizes
                                                    </Badge>
                                                )}
                                                {product.variants.some(v => v.stock_qty !== undefined && v.stock_qty < 10) && (
                                                    <Badge variant="destructive" className="text-xs">
                                                        Low Stock
                                                    </Badge>
                                                )}
                                            </div>
                                        </div>
                                        <div className="p-3 space-y-1">
                                            <p className="font-medium text-sm line-clamp-1">{product.name}</p>
                                            <div className="flex items-center justify-between">
                                                <p className="text-sm font-semibold text-primary">
                                                    ${Math.min(...product.variants.map(v => Number(v.price))).toFixed(2)}
                                                    {product.variants.length > 1 && '+'}
                                                </p>
                                                {product.category && (
                                                    <Badge variant="outline" className="text-xs">
                                                        {product.category.name}
                                                    </Badge>
                                                )}
                                            </div>
                                        </div>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    )}
                </ScrollArea>
            </div>

            {/* Cart Sidebar */}
            <Card className="w-96 m-4 flex flex-col shadow-lg border-2">
                <CardHeader className="pb-3">
                    <CardTitle className="flex items-center gap-2">
                        <ShoppingCartIcon className="size-5" />
                        Current Order
                        {cart.items.length > 0 && (
                            <Badge variant="secondary" className="ml-auto">
                                {cart.items.reduce((acc, item) => acc + item.quantity, 0)} items
                            </Badge>
                        )}
                    </CardTitle>
                </CardHeader>
                <Separator />
                <CardContent className="flex-1 p-0 overflow-hidden flex flex-col">
                    <ScrollArea className="flex-1 p-4">
                        {cart.items.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-full text-muted-foreground py-12">
                                <ShoppingCartIcon className="size-16 mb-3 opacity-50" />
                                <p className="text-sm">Cart is empty</p>
                                <p className="text-xs mt-1">Add products to get started</p>
                            </div>
                        ) : (
                            <div className="space-y-3">
                                {cart.items.map(item => {
                                    const stockQty = getVariantStock(item.variant_id)
                                    const isLowStock = stockQty !== undefined && stockQty < 10
                                    const isOutOfStock = stockQty !== undefined && item.quantity > stockQty

                                    return (
                                        <div key={item.variant_id} className={`flex gap-3 p-3 rounded-lg border bg-card hover:bg-muted/50 transition-colors ${isOutOfStock ? 'border-destructive' : ''}`}>
                                            <div className="flex-1 min-w-0">
                                                <p className="font-medium text-sm truncate">{item.product_name}</p>
                                                <p className="text-xs text-muted-foreground">{item.size_name}</p>
                                                <p className="text-sm font-semibold text-primary mt-1">
                                                    ${Number(item.price).toFixed(2)} × {item.quantity} = ${(Number(item.price) * item.quantity).toFixed(2)}
                                                </p>
                                                {isOutOfStock && (
                                                    <p className="text-xs text-destructive mt-1">⚠ Only {stockQty} in stock</p>
                                                )}
                                                {isLowStock && !isOutOfStock && (
                                                    <p className="text-xs text-orange-600 mt-1">Low stock: {stockQty} left</p>
                                                )}
                                            </div>
                                            <div className="flex flex-col gap-1">
                                                <div className="flex items-center gap-1 bg-muted rounded-md">
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-7 w-7"
                                                        onClick={() => cart.updateQuantity(item.variant_id, item.quantity - 1)}
                                                    >
                                                        <MinusIcon className="size-3" />
                                                    </Button>
                                                    <span className="w-8 text-center text-sm font-medium">{item.quantity}</span>
                                                    <Button
                                                        variant="ghost"
                                                        size="icon"
                                                        className="h-7 w-7"
                                                        onClick={() => cart.updateQuantity(item.variant_id, item.quantity + 1)}
                                                        disabled={stockQty !== undefined && item.quantity >= stockQty}
                                                    >
                                                        <PlusIcon className="size-3" />
                                                    </Button>
                                                </div>
                                                <Button
                                                    variant="ghost"
                                                    size="icon"
                                                    className="h-7 w-7 text-destructive hover:text-destructive"
                                                    onClick={() => cart.removeItem(item.variant_id)}
                                                >
                                                    <TrashIcon className="size-3" />
                                                </Button>
                                            </div>
                                        </div>
                                    )
                                })}
                            </div>
                        )}
                    </ScrollArea>

                    {cart.items.length > 0 && (
                        <>
                            <Separator />
                            <div className="p-4 space-y-3 bg-muted/30">
                                {/* Stock Warning */}
                                {cart.items.some(item => {
                                    const stockQty = getVariantStock(item.variant_id)
                                    return stockQty !== undefined && item.quantity > stockQty
                                }) && (
                                        <div className="p-2 bg-destructive/10 border border-destructive rounded-lg">
                                            <p className="text-xs text-destructive font-medium">
                                                ⚠ Some items exceed available stock
                                            </p>
                                        </div>
                                    )}

                                <div className="space-y-2 text-sm">
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Subtotal</span>
                                        <span className="font-medium">${subtotal.toFixed(2)}</span>
                                    </div>
                                    <div className="flex justify-between">
                                        <span className="text-muted-foreground">Tax ({(cart.taxRate * 100).toFixed(0)}%)</span>
                                        <span className="font-medium">${tax.toFixed(2)}</span>
                                    </div>
                                    {discount > 0 && (
                                        <div className="flex justify-between text-green-600">
                                            <span className="flex items-center gap-1">
                                                <PercentIcon className="size-3" />
                                                Discount
                                            </span>
                                            <span className="font-medium">-${discount.toFixed(2)}</span>
                                        </div>
                                    )}
                                    <Separator />
                                    <div className="flex justify-between text-lg font-bold">
                                        <span>Total</span>
                                        <span className="text-primary">${total.toFixed(2)}</span>
                                    </div>
                                </div>

                                <div className="flex gap-2">
                                    <Button
                                        variant="outline"
                                        className="flex-1"
                                        onClick={() => cart.clearCart()}
                                    >
                                        <XIcon className="size-4 mr-2" />
                                        Clear
                                    </Button>
                                    <Button
                                        className="flex-1"
                                        onClick={() => setCheckoutOpen(true)}
                                    >
                                        <CreditCardIcon className="size-4 mr-2" />
                                        Checkout (F2)
                                    </Button>
                                </div>
                            </div>
                        </>
                    )}
                </CardContent>
            </Card>

            {/* Variant Selection Dialog */}
            <Dialog open={!!selectedVariant} onOpenChange={() => setSelectedVariant(null)}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Select Size</DialogTitle>
                    </DialogHeader>
                    {selectedVariant && (
                        <div className="space-y-4">
                            <div className="text-center">
                                <h3 className="font-semibold text-lg">{selectedVariant.product.name}</h3>
                                {selectedVariant.product.description && (
                                    <p className="text-sm text-muted-foreground mt-1">
                                        {selectedVariant.product.description}
                                    </p>
                                )}
                            </div>
                            <RadioGroup
                                value={selectedVariant.variant.id.toString()}
                                onValueChange={(value) => {
                                    const variant = selectedVariant.product.variants.find(v => v.id.toString() === value)
                                    if (variant) setSelectedVariant({ ...selectedVariant, variant })
                                }}
                            >
                                {selectedVariant.product.variants.map(variant => (
                                    <div key={variant.id} className="flex items-center space-x-3 border rounded-lg p-3 hover:bg-muted/50 cursor-pointer">
                                        <RadioGroupItem value={variant.id.toString()} id={`variant-${variant.id}`} />
                                        <Label htmlFor={`variant-${variant.id}`} className="flex-1 cursor-pointer">
                                            <div className="flex justify-between items-center">
                                                <span className="font-medium">{variant.size_name}</span>
                                                <span className="font-semibold text-primary">${Number(variant.price).toFixed(2)}</span>
                                            </div>
                                            {variant.stock_qty !== undefined && (
                                                <p className={`text-xs mt-1 ${variant.stock_qty < 10 ? 'text-destructive' : 'text-muted-foreground'}`}>
                                                    Stock: {variant.stock_qty} {variant.stock_qty < 10 && '(Low)'}
                                                </p>
                                            )}
                                        </Label>
                                    </div>
                                ))}
                            </RadioGroup>
                            <Button
                                className="w-full"
                                onClick={() => handleAddToCart(selectedVariant.product, selectedVariant.variant)}
                            >
                                Add to Cart
                            </Button>
                        </div>
                    )}
                </DialogContent>
            </Dialog>

            {/* Checkout Dialog */}
            <Dialog open={checkoutOpen} onOpenChange={setCheckoutOpen}>
                <DialogContent className="sm:max-w-md">
                    <DialogHeader>
                        <DialogTitle>Complete Order</DialogTitle>
                    </DialogHeader>
                    <div className="space-y-4">
                        <div className="space-y-2">
                            <Label>Order Type</Label>
                            <RadioGroup value={orderType} onValueChange={(v) => {
                                setOrderType(v as any)
                                if (v === "takeaway") setSelectedTable(null)
                            }}>
                                <div className="flex items-center space-x-3 border rounded-lg p-3 hover:bg-muted/50 cursor-pointer">
                                    <RadioGroupItem value="dine_in" id="dine_in" />
                                    <Label htmlFor="dine_in" className="flex-1 cursor-pointer flex items-center gap-2">
                                        <UtensilsIcon className="size-4" />
                                        Dine In
                                    </Label>
                                </div>
                                <div className="flex items-center space-x-3 border rounded-lg p-3 hover:bg-muted/50 cursor-pointer">
                                    <RadioGroupItem value="takeaway" id="takeaway" />
                                    <Label htmlFor="takeaway" className="flex-1 cursor-pointer flex items-center gap-2">
                                        <PackageIcon className="size-4" />
                                        Takeaway
                                    </Label>
                                </div>
                            </RadioGroup>
                        </div>

                        {/* Table Selection for Dine-In */}
                        {orderType === "dine_in" && (
                            <div className="space-y-2">
                                <Label>Select Table {!selectedTable && <span className="text-destructive">*</span>}</Label>
                                <ScrollArea className="h-32 border rounded-lg p-2">
                                    <div className="grid grid-cols-3 gap-2">
                                        {tables.filter(t => t.status === 'available').map(table => (
                                            <Button
                                                key={table.id}
                                                variant={selectedTable === table.id ? "default" : "outline"}
                                                size="sm"
                                                onClick={() => setSelectedTable(table.id)}
                                                className="h-16 flex flex-col"
                                            >
                                                <span className="font-bold">Table {table.number}</span>
                                                <span className="text-xs">{table.capacity} seats</span>
                                            </Button>
                                        ))}
                                    </div>
                                    {tables.filter(t => t.status === 'available').length === 0 && (
                                        <p className="text-sm text-muted-foreground text-center py-4">
                                            No tables available
                                        </p>
                                    )}
                                </ScrollArea>
                            </div>
                        )}

                        <div className="space-y-2">
                            <Label>Payment Method</Label>
                            <RadioGroup value={paymentMethod} onValueChange={(v) => {
                                setPaymentMethod(v as any)
                                if (v === "card") setCashAmount("")
                            }}>
                                <div className="flex items-center space-x-3 border rounded-lg p-3 hover:bg-muted/50 cursor-pointer">
                                    <RadioGroupItem value="cash" id="cash" />
                                    <Label htmlFor="cash" className="flex-1 cursor-pointer flex items-center gap-2">
                                        <BanknoteIcon className="size-4" />
                                        Cash
                                    </Label>
                                </div>
                                <div className="flex items-center space-x-3 border rounded-lg p-3 hover:bg-muted/50 cursor-pointer">
                                    <RadioGroupItem value="card" id="card" />
                                    <Label htmlFor="card" className="flex-1 cursor-pointer flex items-center gap-2">
                                        <CreditCardIcon className="size-4" />
                                        Card
                                    </Label>
                                </div>
                            </RadioGroup>
                        </div>

                        {/* Cash Amount Input */}
                        {paymentMethod === "cash" && (
                            <div className="space-y-2">
                                <Label htmlFor="cash-amount">Cash Amount {!cashAmount && <span className="text-destructive">*</span>}</Label>
                                <Input
                                    id="cash-amount"
                                    type="number"
                                    step="0.01"
                                    min={total}
                                    placeholder={`Min: $${total.toFixed(2)}`}
                                    value={cashAmount}
                                    onChange={(e) => setCashAmount(e.target.value)}
                                    className="text-lg font-semibold"
                                />
                                {/* Quick Amount Buttons */}
                                <div className="flex gap-2 flex-wrap">
                                    {suggestedAmounts.map(amount => (
                                        <Button
                                            key={amount}
                                            type="button"
                                            variant="outline"
                                            size="sm"
                                            onClick={() => setCashAmount(amount.toString())}
                                            className="flex-1"
                                        >
                                            ${amount}
                                        </Button>
                                    ))}
                                    <Button
                                        type="button"
                                        variant="outline"
                                        size="sm"
                                        onClick={() => setCashAmount(total.toFixed(2))}
                                        className="flex-1"
                                    >
                                        Exact
                                    </Button>
                                </div>
                                {cashAmount && parseFloat(cashAmount) >= total && (
                                    <div className="flex items-center justify-between p-2 bg-green-50 dark:bg-green-950 rounded-lg">
                                        <span className="text-sm font-medium text-green-700 dark:text-green-300">Change:</span>
                                        <span className="text-lg font-bold text-green-700 dark:text-green-300">
                                            ${(parseFloat(cashAmount) - total).toFixed(2)}
                                        </span>
                                    </div>
                                )}
                            </div>
                        )}

                        <Separator />

                        <div className="space-y-2 text-sm bg-muted/50 p-3 rounded-lg">
                            <div className="flex justify-between">
                                <span>Subtotal</span>
                                <span>${subtotal.toFixed(2)}</span>
                            </div>
                            <div className="flex justify-between">
                                <span>Tax</span>
                                <span>${tax.toFixed(2)}</span>
                            </div>
                            {discount > 0 && (
                                <div className="flex justify-between text-green-600">
                                    <span>Discount</span>
                                    <span>-${discount.toFixed(2)}</span>
                                </div>
                            )}
                            <Separator />
                            <div className="flex justify-between text-lg font-bold">
                                <span>Total</span>
                                <span className="text-primary">${total.toFixed(2)}</span>
                            </div>
                        </div>
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setCheckoutOpen(false)} disabled={processingOrder}>
                            Cancel
                        </Button>
                        <Button onClick={handleCheckout} disabled={processingOrder}>
                            {processingOrder ? (
                                <>
                                    <Loader2Icon className="size-4 mr-2 animate-spin" />
                                    Processing...
                                </>
                            ) : (
                                <>
                                    <CreditCardIcon className="size-4 mr-2" />
                                    Confirm Payment
                                </>
                            )}
                        </Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </div>
    )
}

'use client'

import { useState, useEffect } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card'
import { Badge } from '@/components/ui/badge'
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog'
import { Label } from '@/components/ui/label'
import { Textarea } from '@/components/ui/textarea'
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select'
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table'
import { Plus, Search, Edit, Trash2, Eye, Package, Calendar, DollarSign } from 'lucide-react'
import { toast } from 'react-hot-toast'
import axios from '@/lib/axios'

interface PurchaseOrder {
    id: number
    po_number: string
    supplier_id: number
    supplier?: {
        id: number
        name: string
    }
    order_date: string
    expected_date: string
    received_date?: string
    status: 'pending' | 'ordered' | 'received' | 'cancelled'
    subtotal: number
    tax_amount: number
    total_amount: number
    notes: string
    created_at: string
    updated_at: string
    items?: PurchaseOrderItem[]
}

interface PurchaseOrderItem {
    id: number
    product_id: number
    product?: {
        id: number
        name: string
        sku: string
    }
    quantity_ordered: number
    quantity_received: number
    unit_cost: number
    total_cost: number
}

interface Supplier {
    id: number
    name: string
}

interface Product {
    id: number
    name: string
    sku: string
    cost_price: number
}

export default function PurchaseOrdersPage() {
    const [purchaseOrders, setPurchaseOrders] = useState<PurchaseOrder[]>([])
    const [suppliers, setSuppliers] = useState<Supplier[]>([])
    const [products, setProducts] = useState<Product[]>([])
    const [loading, setLoading] = useState(true)
    const [searchTerm, setSearchTerm] = useState('')
    const [isDialogOpen, setIsDialogOpen] = useState(false)
    const [editingPO, setEditingPO] = useState<PurchaseOrder | null>(null)
    const [formData, setFormData] = useState({
        supplier_id: '',
        expected_date: '',
        notes: '',
        items: [{ product_id: '', quantity_ordered: 1, unit_cost: 0 }]
    })

    useEffect(() => {
        fetchData()
    }, [])

    const fetchData = async () => {
        try {
            const [poResponse, suppliersResponse, productsResponse] = await Promise.all([
                axios.get('/purchase-orders'),
                axios.get('/suppliers'),
                axios.get('/products')
            ])

            setPurchaseOrders(poResponse.data.data || [])
            setSuppliers(suppliersResponse.data.data || [])
            setProducts(productsResponse.data.data || [])
        } catch (error) {
            toast.error('Failed to fetch data')
            console.error('Error fetching data:', error)
        } finally {
            setLoading(false)
        }
    }

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault()
        try {
            const payload = {
                ...formData,
                supplier_id: parseInt(formData.supplier_id),
                items: formData.items.map(item => ({
                    ...item,
                    product_id: parseInt(item.product_id),
                    quantity_ordered: parseInt(item.quantity_ordered.toString()),
                    unit_cost: parseFloat(item.unit_cost.toString())
                }))
            }

            if (editingPO) {
                await axios.put(`/api/purchase-orders/${editingPO.id}`, payload)
                toast.success('Purchase order updated successfully')
            } else {
                await axios.post('/purchase-orders', payload)
                toast.success('Purchase order created successfully')
            }

            setIsDialogOpen(false)
            setEditingPO(null)
            resetForm()
            fetchData()
        } catch (error) {
            toast.error('Failed to save purchase order')
            console.error('Error saving purchase order:', error)
        }
    }

    const handleEdit = (po: PurchaseOrder) => {
        setEditingPO(po)
        setFormData({
            supplier_id: po.supplier_id.toString(),
            expected_date: po.expected_date.split('T')[0],
            notes: po.notes,
            items: po.items?.map(item => ({
                product_id: item.product_id.toString(),
                quantity_ordered: item.quantity_ordered,
                unit_cost: item.unit_cost
            })) || [{ product_id: '', quantity_ordered: 1, unit_cost: 0 }]
        })
        setIsDialogOpen(true)
    }

    const handleDelete = async (id: number) => {
        if (confirm('Are you sure you want to delete this purchase order?')) {
            try {
                await axios.delete(`/purchase-orders/${id}`)
                toast.success('Purchase order deleted successfully')
                fetchData()
            } catch (error) {
                toast.error('Failed to delete purchase order')
                console.error('Error deleting purchase order:', error)
            }
        }
    }

    const handleStatusUpdate = async (id: number, status: string) => {
        try {
            await axios.patch(`/purchase-orders/${id}/status`, { status })
            toast.success('Status updated successfully')
            fetchData()
        } catch (error) {
            toast.error('Failed to update status')
            console.error('Error updating status:', error)
        }
    }

    const resetForm = () => {
        setFormData({
            supplier_id: '',
            expected_date: '',
            notes: '',
            items: [{ product_id: '', quantity_ordered: 1, unit_cost: 0 }]
        })
    }

    const addItem = () => {
        setFormData({
            ...formData,
            items: [...formData.items, { product_id: '', quantity_ordered: 1, unit_cost: 0 }]
        })
    }

    const removeItem = (index: number) => {
        setFormData({
            ...formData,
            items: formData.items.filter((_, i) => i !== index)
        })
    }

    const updateItem = (index: number, field: string, value: any) => {
        const updatedItems = [...formData.items]
        updatedItems[index] = { ...updatedItems[index], [field]: value }
        setFormData({ ...formData, items: updatedItems })
    }

    const filteredPOs = purchaseOrders.filter(po =>
        po.po_number.toLowerCase().includes(searchTerm.toLowerCase()) ||
        po.supplier?.name.toLowerCase().includes(searchTerm.toLowerCase())
    )

    const getStatusColor = (status: string) => {
        switch (status) {
            case 'pending': return 'bg-yellow-100 text-yellow-800'
            case 'ordered': return 'bg-blue-100 text-blue-800'
            case 'received': return 'bg-green-100 text-green-800'
            case 'cancelled': return 'bg-red-100 text-red-800'
            default: return 'bg-gray-100 text-gray-800'
        }
    }

    if (loading) {
        return <div className="flex items-center justify-center h-64">Loading...</div>
    }

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Purchase Orders</h1>
                    <p className="text-muted-foreground">Manage your inventory procurement</p>
                </div>
                <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                    <DialogTrigger asChild>
                        <Button onClick={() => { resetForm(); setEditingPO(null) }}>
                            <Plus className="mr-2 h-4 w-4" />
                            Create Purchase Order
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="max-w-4xl max-h-[90vh] overflow-y-auto">
                        <DialogHeader>
                            <DialogTitle>{editingPO ? 'Edit Purchase Order' : 'Create New Purchase Order'}</DialogTitle>
                            <DialogDescription>
                                {editingPO ? 'Update purchase order details' : 'Create a new purchase order for inventory procurement'}
                            </DialogDescription>
                        </DialogHeader>
                        <form onSubmit={handleSubmit} className="space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-2">
                                    <Label htmlFor="supplier_id">Supplier *</Label>
                                    <Select value={formData.supplier_id} onValueChange={(value) => setFormData({ ...formData, supplier_id: value })}>
                                        <SelectTrigger>
                                            <SelectValue placeholder="Select supplier" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {suppliers.map((supplier) => (
                                                <SelectItem key={supplier.id} value={supplier.id.toString()}>
                                                    {supplier.name}
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor="expected_date">Expected Date *</Label>
                                    <Input
                                        id="expected_date"
                                        type="date"
                                        value={formData.expected_date}
                                        onChange={(e) => setFormData({ ...formData, expected_date: e.target.value })}
                                        required
                                    />
                                </div>
                            </div>

                            <div className="space-y-4">
                                <div className="flex justify-between items-center">
                                    <Label>Items</Label>
                                    <Button type="button" variant="outline" size="sm" onClick={addItem}>
                                        <Plus className="h-4 w-4 mr-2" />
                                        Add Item
                                    </Button>
                                </div>

                                {formData.items.map((item, index) => (
                                    <div key={index} className="grid grid-cols-5 gap-2 items-end p-4 border rounded-lg">
                                        <div className="space-y-2">
                                            <Label>Product</Label>
                                            <Select
                                                value={item.product_id}
                                                onValueChange={(value) => {
                                                    updateItem(index, 'product_id', value)
                                                    const product = products.find(p => p.id.toString() === value)
                                                    if (product) {
                                                        updateItem(index, 'unit_cost', product.cost_price)
                                                    }
                                                }}
                                            >
                                                <SelectTrigger>
                                                    <SelectValue placeholder="Select product" />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    {products.map((product) => (
                                                        <SelectItem key={product.id} value={product.id.toString()}>
                                                            {product.name} ({product.sku})
                                                        </SelectItem>
                                                    ))}
                                                </SelectContent>
                                            </Select>
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Quantity</Label>
                                            <Input
                                                type="number"
                                                min="1"
                                                value={item.quantity_ordered}
                                                onChange={(e) => updateItem(index, 'quantity_ordered', parseInt(e.target.value) || 1)}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Unit Cost</Label>
                                            <Input
                                                type="number"
                                                step="0.01"
                                                min="0"
                                                value={item.unit_cost}
                                                onChange={(e) => updateItem(index, 'unit_cost', parseFloat(e.target.value) || 0)}
                                            />
                                        </div>
                                        <div className="space-y-2">
                                            <Label>Total</Label>
                                            <Input
                                                value={`$${(item.quantity_ordered * item.unit_cost).toFixed(2)}`}
                                                disabled
                                            />
                                        </div>
                                        <Button
                                            type="button"
                                            variant="outline"
                                            size="sm"
                                            onClick={() => removeItem(index)}
                                            disabled={formData.items.length === 1}
                                        >
                                            <Trash2 className="h-4 w-4" />
                                        </Button>
                                    </div>
                                ))}
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="notes">Notes</Label>
                                <Textarea
                                    id="notes"
                                    value={formData.notes}
                                    onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
                                    rows={3}
                                />
                            </div>

                            <DialogFooter>
                                <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>
                                    Cancel
                                </Button>
                                <Button type="submit">
                                    {editingPO ? 'Update Purchase Order' : 'Create Purchase Order'}
                                </Button>
                            </DialogFooter>
                        </form>
                    </DialogContent>
                </Dialog>
            </div>

            <Card>
                <CardHeader>
                    <CardTitle>Purchase Orders</CardTitle>
                    <CardDescription>
                        Total orders: {purchaseOrders.length}
                    </CardDescription>
                    <div className="flex items-center space-x-2">
                        <Search className="h-4 w-4 text-muted-foreground" />
                        <Input
                            placeholder="Search purchase orders..."
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="max-w-sm"
                        />
                    </div>
                </CardHeader>
                <CardContent>
                    <Table>
                        <TableHeader>
                            <TableRow>
                                <TableHead>PO Number</TableHead>
                                <TableHead>Supplier</TableHead>
                                <TableHead>Order Date</TableHead>
                                <TableHead>Expected Date</TableHead>
                                <TableHead>Total Amount</TableHead>
                                <TableHead>Status</TableHead>
                                <TableHead>Actions</TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {filteredPOs.map((po) => (
                                <TableRow key={po.id}>
                                    <TableCell>
                                        <div className="font-medium flex items-center">
                                            <Package className="h-4 w-4 mr-2" />
                                            {po.po_number}
                                        </div>
                                    </TableCell>
                                    <TableCell>{po.supplier?.name}</TableCell>
                                    <TableCell>
                                        <div className="flex items-center">
                                            <Calendar className="h-4 w-4 mr-2" />
                                            {new Date(po.order_date).toLocaleDateString()}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center">
                                            <Calendar className="h-4 w-4 mr-2" />
                                            {new Date(po.expected_date).toLocaleDateString()}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center font-medium">
                                            <DollarSign className="h-4 w-4 mr-1" />
                                            {po.total_amount.toFixed(2)}
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <Select
                                            value={po.status}
                                            onValueChange={(value) => handleStatusUpdate(po.id, value)}
                                        >
                                            <SelectTrigger className="w-32">
                                                <Badge className={getStatusColor(po.status)}>
                                                    {po.status.toUpperCase()}
                                                </Badge>
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="pending">Pending</SelectItem>
                                                <SelectItem value="ordered">Ordered</SelectItem>
                                                <SelectItem value="received">Received</SelectItem>
                                                <SelectItem value="cancelled">Cancelled</SelectItem>
                                            </SelectContent>
                                        </Select>
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center space-x-2">
                                            <Button variant="outline" size="sm">
                                                <Eye className="h-4 w-4" />
                                            </Button>
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => handleEdit(po)}
                                            >
                                                <Edit className="h-4 w-4" />
                                            </Button>
                                            <Button
                                                variant="outline"
                                                size="sm"
                                                onClick={() => handleDelete(po.id)}
                                            >
                                                <Trash2 className="h-4 w-4" />
                                            </Button>
                                        </div>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                    {filteredPOs.length === 0 && (
                        <div className="text-center py-8 text-muted-foreground">
                            No purchase orders found
                        </div>
                    )}
                </CardContent>
            </Card>
        </div>
    )
}
